#!/usr/bin/env node
/**
 * Runtime-evidence-based coverage report generator (Phase 40, INFRA-23)
 * Run: pnpm coverage:generate
 * Requires:
 *   tests/sdk-verification/coverage/symbol-execution.json
 *     (generated by running: pnpm test:sdk with setupFiles capturing hits)
 *   tests/sdk-verification/coverage/vitest-evidence.json
 *     (generated by: pnpm test:sdk --reporter=json
 *       --outputFile.json=tests/sdk-verification/coverage/vitest-evidence.json)
 *
 * Algorithm:
 *   1. Build passedFiles from vitest-evidence.json (which test files ran and passed).
 *   2. Build symbol -> evidenceEntries[] from symbol-execution.json.
 *   3. Mark a symbol 'live' when at least one of its evidence files is in passedFiles.
 *   4. Emit a provenance block naming the two input artifacts and the phase.
 *   5. Store per-symbol evidence as { hitCount, testFiles } inside an `evidence` object.
 *      No top-level `testFile` field — all provenance comes from runtime execution.
 *
 * Replaces the hand-authored EVIDENCE_MAP approach used in Phase 34.
 */
import { readFileSync, writeFileSync, readdirSync, existsSync } from 'node:fs';
import { join, dirname, relative } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, '../../..');
const manifestsDir = join(root, 'tools/sdk-surface/manifests');

const vitestEvidencePath = join(__dirname, 'vitest-evidence.json');
const symbolExecutionPath = join(__dirname, 'symbol-execution.json');
const outputPath = join(__dirname, 'coverage-report.json');

// ── 1. Load vitest-evidence.json ──────────────────────────────────────────────

if (!existsSync(vitestEvidencePath)) {
  console.error(`ERROR: vitest-evidence.json not found at ${vitestEvidencePath}`);
  console.error('Generate it with:');
  console.error(
    '  pnpm test:sdk --reporter=verbose --reporter=json' +
    ' --outputFile.json=tests/sdk-verification/coverage/vitest-evidence.json'
  );
  process.exit(1);
}

const vitestEvidence = JSON.parse(readFileSync(vitestEvidencePath, 'utf8'));
if (!Array.isArray(vitestEvidence.testResults)) {
  console.error('ERROR: vitest-evidence.json is missing testResults array — regenerate it.');
  process.exit(1);
}

// Build set of test files that ran and passed.
// Vitest emits absolute paths; normalize to relative from repo root.
const sdkVerificationPrefix = 'tests/sdk-verification/';
const passedFiles = new Set<string>();
for (const result of vitestEvidence.testResults) {
  const relFromRoot = relative(root, result.name);
  if (result.status === 'passed') {
    passedFiles.add(relFromRoot);
  }
}
console.log(`Evidence: ${passedFiles.size} test files passed.`);

// ── 2. Load symbol-execution.json ─────────────────────────────────────────────

if (!existsSync(symbolExecutionPath)) {
  console.error(`ERROR: symbol-execution.json not found at ${symbolExecutionPath}`);
  console.error('Generate it by running the SDK verification suite:');
  console.error(
    '  pnpm test:sdk --reporter=verbose --reporter=json' +
    ' --outputFile.json=tests/sdk-verification/coverage/vitest-evidence.json'
  );
  process.exit(1);
}

const symbolExecution = JSON.parse(readFileSync(symbolExecutionPath, 'utf8'));
if (!symbolExecution.generatedAt || !Array.isArray(symbolExecution.hits)) {
  console.error('ERROR: symbol-execution.json is malformed — missing generatedAt or hits array.');
  process.exit(1);
}

// Build a map from symbol key -> set of test files that hit it.
// Key format matches manifest: "@package@version/SymbolPath"
interface HitEntry {
  symbol: string;
  testFile: string;
  hitCount: number;
}

const symbolHitMap = new Map<string, { totalHitCount: number; testFiles: Map<string, number> }>();
for (const hit of symbolExecution.hits as HitEntry[]) {
  if (!symbolHitMap.has(hit.symbol)) {
    symbolHitMap.set(hit.symbol, { totalHitCount: 0, testFiles: new Map() });
  }
  const entry = symbolHitMap.get(hit.symbol)!;
  entry.totalHitCount += hit.hitCount;
  const existing = entry.testFiles.get(hit.testFile) ?? 0;
  entry.testFiles.set(hit.testFile, existing + hit.hitCount);
}
console.log(`Runtime evidence: ${symbolHitMap.size} unique symbols hit across ${symbolExecution.hitCount} hit records.`);

// ── 3. Manifest loading types ─────────────────────────────────────────────────

interface ManifestSymbol { kind: string; members?: string[] }
interface Manifest { package: string; version: string; generatedAt: string; symbolCount: number; symbols: Record<string, ManifestSymbol> }

// ── 4. Build per-symbol live/deferred status from runtime evidence ─────────────

/**
 * Determine if a symbol is live based on runtime evidence.
 *
 * A symbol is 'live' when at least one test file that hit it is in passedFiles.
 * Returns the evidence object for the symbol (hitCount and testFiles that are in passedFiles).
 * Returns null if no evidence qualifies the symbol as live.
 */
function resolveSymbolStatus(symbolKey: string): {
  tier: 'live' | 'deferred';
  evidence: { hitCount: number; testFiles: string[] } | null;
} {
  const hitData = symbolHitMap.get(symbolKey);
  if (!hitData) {
    return { tier: 'deferred', evidence: null };
  }

  // Filter to only test files that are in passedFiles
  const qualifyingFiles: Array<{ file: string; hitCount: number }> = [];
  let qualifyingHitCount = 0;
  for (const [testFile, hitCount] of hitData.testFiles.entries()) {
    // testFile from symbol-execution.json is an absolute path; normalize it
    const relFile = testFile.startsWith('/')
      ? relative(root, testFile)
      : testFile;
    if (passedFiles.has(relFile)) {
      qualifyingFiles.push({ file: relFile, hitCount });
      qualifyingHitCount += hitCount;
    }
  }

  if (qualifyingFiles.length === 0) {
    return { tier: 'deferred', evidence: null };
  }

  return {
    tier: 'live',
    evidence: {
      hitCount: qualifyingHitCount,
      testFiles: qualifyingFiles.map(f => f.file),
    },
  };
}

// ── 5. Process all manifests ───────────────────────────────────────────────────

const packages: Record<
  string,
  Record<
    string,
    {
      tier: 'live' | 'deferred';
      evidence: { hitCount: number; testFiles: string[] } | null;
    }
  >
> = {};

let totalLive = 0;
let totalDeferred = 0;

const manifestFiles = readdirSync(manifestsDir).filter(f => f.endsWith('.json'));

for (const file of manifestFiles) {
  const manifest: Manifest = JSON.parse(readFileSync(join(manifestsDir, file), 'utf8'));
  const pkgKey = `${manifest.package}@${manifest.version}`;
  packages[pkgKey] = {};

  for (const [symbolName, symbolDef] of Object.entries(manifest.symbols)) {
    const topKey = `${pkgKey}/${symbolName}`;
    const resolved = resolveSymbolStatus(topKey);
    packages[pkgKey][symbolName] = resolved;
    if (resolved.tier === 'live') totalLive++; else totalDeferred++;

    if (symbolDef.members) {
      for (const member of symbolDef.members) {
        const memberPath = `${symbolName}.${member}`;
        const memberKey = `${pkgKey}/${memberPath}`;
        const memberResolved = resolveSymbolStatus(memberKey);
        packages[pkgKey][memberPath] = memberResolved;
        if (memberResolved.tier === 'live') totalLive++; else totalDeferred++;
      }
    }
  }
}

// ── 6. Emit the report ────────────────────────────────────────────────────────

const report = {
  $schema: 'https://sandpiper.dev/schemas/coverage-report.json',
  generatedAt: new Date().toISOString(),
  phase: '40',
  note: 'Phase 40: SDK coverage derived from runtime symbol execution evidence (INFRA-23). ' +
        'Symbol live/deferred status comes from runtime hits joined with passing test files, ' +
        'not from a hand-authored symbol-to-test-file attribution map.',
  // Top-level provenance fields (INFRA-25 truthfulness-contract.test.ts assertions)
  evidenceSource: 'runtime-symbol-execution' as const,
  executionArtifact: 'tests/sdk-verification/coverage/symbol-execution.json' as const,
  vitestArtifact: 'tests/sdk-verification/coverage/vitest-evidence.json' as const,
  // Structured provenance block for richer metadata
  provenance: {
    evidenceSource: 'runtime-symbol-execution',
    executionArtifact: 'tests/sdk-verification/coverage/symbol-execution.json',
    vitestArtifact: 'tests/sdk-verification/coverage/vitest-evidence.json',
    symbolExecutionGeneratedAt: symbolExecution.generatedAt as string,
    totalSymbolHits: symbolHitMap.size,
  },
  packages,
  summary: { live: totalLive, stub: 0, deferred: totalDeferred },
};

writeFileSync(outputPath, JSON.stringify(report, null, 2) + '\n');
console.log(`Coverage report written to ${outputPath}`);
console.log(`Summary: ${totalLive} live, 0 stub, ${totalDeferred} deferred`);
if (totalLive >= 222) {
  console.log(`INFRA-22/23: runtime-evidence live count ${totalLive} >= 222 required. Phase 40 transition complete.`);
} else {
  console.error(`INFRA-22/23 WARNING: runtime-evidence live count ${totalLive} < 222. Check that test:sdk ran fully and symbol-execution.json is fresh.`);
}
